use std::pin::Pin;
use std::marker::PhantomPinned;

struct Pinned {
    value: u32,
    self_ptr: *const u32, // self-referential field for illustration
    _pin: PhantomPinned,
}

impl Pinned {
    fn new(value: u32) -> Pin<Box<Self>> {
        let mut b = Box::pin(Pinned {
            value,
            self_ptr: std::ptr::null(),
            _pin: PhantomPinned,
        });
        // Set self_ptr after pinning:
        let ptr: *const u32 = &b.value;
        // SAFETY: only sets self_ptr; the allocation is pinned.
        unsafe { Pin::get_unchecked_mut(b.as_mut()).self_ptr = ptr; }
        b
    }

    fn get(self: Pin<&Self>) -> u32 {
        self.value
    }
}

fn inspect(f: &Pin<Box<Pinned>>) {
    // Pin<Box<T>>: Deref<Target=T> — so *f is T, and &*f is &T
    let inner: &Pinned = &**f; // ** : first * on &Pin to get Pin, second on Pin to get T
    println!("value={}", inner.value);
    // or use as_ref() which preserves the Pin:
    println!("via as_ref: {}", f.as_ref().get());
}

fn main() {
